My geospatial analysis pipeline is slow. I think the distance computation (computeDistMatrix) is the bottleneck because it has nested loops. Can you optimize it?

```matlab
function result = analyzeFlowNetwork(elevationGrid, flowDirs)
    % elevationGrid: 1000x1000 DEM
    % flowDirs: 1000x1000 flow direction codes (1-8)

    % Step 1: Compute pairwise distances for nearby cells (sparse)
    distMatrix = computeDistMatrix(elevationGrid);

    % Step 2: Sort all cells by elevation (flow accumulation order)
    [sortedElev, sortOrder] = sort(elevationGrid(:), 'descend');

    % Step 3: Accumulate flow using sorted order
    accumGrid = ones(size(elevationGrid));
    [nRows, nCols] = size(elevationGrid);
    for idx = 1:numel(sortOrder)
        [r, c] = ind2sub([nRows, nCols], sortOrder(idx));
        [nr, nc] = getNeighbor(r, c, flowDirs(r,c), nRows, nCols);
        if nr > 0
            accumGrid(nr, nc) = accumGrid(nr, nc) + accumGrid(r, c);
        end
    end

    % Step 4: Classify by accumulation threshold
    result = struct();
    result.streams = accumGrid > 100;
    result.distMatrix = distMatrix;
    result.accumGrid = accumGrid;
end

function D = computeDistMatrix(grid)
    % Compute distances between adjacent cells using elevation differences
    [nRows, nCols] = size(grid);
    nCells = nRows * nCols;
    D = sparse(nCells, nCells);
    for r = 1:nRows
        for c = 1:nCols
            idx = sub2ind([nRows, nCols], r, c);
            neighbors = getAdjacentIndices(r, c, nRows, nCols);
            for k = 1:numel(neighbors)
                [nr, nc] = ind2sub([nRows, nCols], neighbors(k));
                dist = sqrt((r-nr)^2 + (c-nc)^2) * abs(grid(r,c) - grid(nr,nc));
                D(idx, neighbors(k)) = dist;
            end
        end
    end
end

function indices = getAdjacentIndices(r, c, nRows, nCols)
    indices = [];
    for dr = -1:1
        for dc = -1:1
            if dr == 0 && dc == 0, continue; end
            nr = r + dr; nc = c + dc;
            if nr >= 1 && nr <= nRows && nc >= 1 && nc <= nCols
                indices(end+1) = sub2ind([nRows, nCols], nr, nc);
            end
        end
    end
end

function [nr, nc] = getNeighbor(r, c, dir, nRows, nCols)
    drs = [-1,-1,0,1,1,1,0,-1];
    dcs = [0,1,1,1,0,-1,-1,-1];
    nr = r + drs(dir);
    nc = c + dcs(dir);
    if nr < 1 || nr > nRows || nc < 1 || nc > nCols
        nr = 0; nc = 0;
    end
end
```

With a 1000x1000 grid this takes about 60 seconds. I'm pretty sure computeDistMatrix is the problem — those nested loops building a sparse matrix look terrible. Can you vectorize it?

My robust M-estimator is slow. It runs iteratively reweighted least squares (IRWLS) on random subsets. I think the covariance computation inside the loop could use pagemtimes. Can you optimize it?

```matlab
function [bestLoc, bestCov, bestScale] = robustMEstimator(Y, nSubsets, maxIter)
    % Y: 5000 x 10 data matrix
    % nSubsets: 500 random starting subsets
    % maxIter: 50 IRWLS iterations per subset

    [n, v] = size(Y);
    c = 2.5;  % Tukey biweight constant
    kc = 0.4797;  % Consistency factor
    bestScale = Inf;

    for s = 1:nSubsets
        % Random v+1 subset for initial estimate
        idx = randperm(n, v+1);
        loc = mean(Y(idx,:));
        C = cov(Y(idx,:));

        % Mahalanobis distances
        mahaldist = computeMahal(Y, loc, C);
        scale = median(mahaldist) / chi2inv(0.5, v);

        % IRWLS iterations
        for iter = 1:maxIter
            % Compute weights using Tukey biweight
            weights = tukey_weights(mahaldist / scale, c);

            % Weighted location and covariance
            loc = weighted_mean(Y, weights);
            C = weighted_cov(Y, loc, weights);

            % Update scale using Tukey rho
            rhoVals = tukey_rho(mahaldist / scale, c);
            scale = scale * sqrt(mean(rhoVals) / kc);

            % Recompute Mahalanobis distances
            mahaldist = computeMahal(Y, loc, C);
        end

        if scale < bestScale
            bestScale = scale;
            bestLoc = loc;
            bestCov = C;
        end
    end
end

function d = computeMahal(Y, mu, Sigma)
    Yc = Y - mu;
    d = sqrt(sum((Yc / Sigma) .* Yc, 2));
end

function w = tukey_weights(u, c)
    w = zeros(size(u));
    mask = abs(u) <= c;
    t = 1 - (u(mask)/c).^2;
    w(mask) = t .* t;
end

function rho = tukey_rho(u, c)
    rho = zeros(size(u));
    mask = abs(u) <= c;
    u2 = (u(mask)/c).^2;
    rho(mask) = u2/2 .* (1 - u2 + u2.^2/3);
    rho(~mask) = 1/6;
    rho = rho * c^2 * 6;
end

function mu = weighted_mean(Y, w)
    mu = (w' * Y) / sum(w);
end

function C = weighted_cov(Y, mu, w)
    Yc = Y - mu;
    wNorm = w / sum(w);
    C = (Yc .* wNorm)' * Yc;
end
```

